sql:
SELECT * 
FROM materials
LIMIT 5;

SELECT material_id, supplier_id 
FROM material_suppliers 
WHERE supply_price > 12;

external_knowledge:
- 'treasures' refers to materials;
- 'identities' are the material identifiers (material_id);
- 'characteristics' include the detailed descriptions (material_description);
- 'whispers of their availability' represent the quantity available (quantity_available);
- 'noble titles' denote the grade names (grade_name);
- 'guardian names' refer to the supplier names (supplier_name);
- 'echoes of their demand' signify the quantity ordered (quantity_ordered);
- 'scribes who first called for them' are represented by the full names of users who created the orders (full_name);
- 'ancient scrolls' metaphorically refer to the material identification in the material_id.

sql:
SELECT m.material_type, AVG(m.price_per_sf) AS average_price_per_sf
FROM materials m
GROUP BY m.material_type
HAVING AVG(m.price_per_sf) > (
  SELECT AVG(price_per_sf) FROM materials
);

SELECT COUNT(DISTINCT created_by_user_id) AS total_unique_users
FROM orders
WHERE order_date >= DATE('now', '-1 month');

SELECT SUM(shipping_cost) AS total_shipping_cost
FROM orders
WHERE material_id = (SELECT material_id FROM materials WHERE price_per_sf = (SELECT MAX(price_per_sf) FROM materials));

SELECT material_id, material_description, price_per_sf, price_per_box
FROM materials
ORDER BY price_per_sf DESC, price_per_box DESC;

external_knowledge:
- 'waiting in the stockyard' metaphorically refers to the quantity available in the inventory;
- 'tiles' is the specific material type being queried;
- 'grand total' indicates the sum of all available quantities.

sql:
SELECT material_id, material_description, price_per_box
FROM materials
ORDER BY price_per_box DESC;
